import React, { useState, useCallback } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Utensils } from 'lucide-react';

const LoginPage = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);

  const { login } = useAuth();
  const addToast = useToast();
  const { theme } = useTheme();
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = useCallback(async (e) => {
    e.preventDefault();
    const { email, password } = formData;

    if (!email || !password) return addToast('Please enter details.', 'error');
    
    setLoading(true);
    try {
      await login(email, password);
      addToast('Welcome back to the kitchen!', 'success');
      navigate('/generate');
    } catch (err) {
      addToast('Could not log in.', 'error');
    } finally {
      setLoading(false);
    }
  }, [formData, login, navigate, addToast]);

  const styles = {
    container: { 
      minHeight: '85vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '1.5rem' 
    },
    card: { 
      width: '100%', 
      maxWidth: '400px', 
      padding: '2.5rem', 
      backgroundColor: '#FFF', 
      borderRadius: '24px', 
      border: '3px solid #5C4033', 
      boxShadow: '8px 8px 0px rgba(92,64,51,0.2)',
      position: 'relative'
    },
    headerIcon: {
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '1rem',
      color: theme.colors.primary || '#5C4033'
    },
    title: { 
      fontSize: '2rem', 
      color: theme.colors.text.main, 
      marginBottom: '2rem', 
      textAlign: 'center',
      fontFamily: theme.fonts.header 
    },
    inputGroup: { 
      position: 'relative', 
      marginBottom: '1.2rem', 
      width: '100%' 
    },
    input: { 
      width: '100%', 
      padding: '1rem 3.5rem 1rem 1rem', 
      backgroundColor: '#FFFBEB', 
      border: '2px solid #E6DACD', 
      borderRadius: '12px', 
      color: theme.colors.text.main, 
      fontSize: '1rem', 
      outline: 'none',
      boxSizing: 'border-box',
      transition: 'border-color 0.2s ease'
    },
    toggleBtn: { 
      position: 'absolute', 
      right: '15px', 
      top: '50%', 
      transform: 'translateY(-50%)', 
      background: 'none', 
      border: 'none', 
      color: theme.colors.text.muted, 
      cursor: 'pointer', 
      display: 'flex', 
      alignItems: 'center',
      zIndex: 10,
      fontSize: '1.2rem'
    },
    button: { 
      width: '100%', 
      padding: '1rem', 
      marginTop: '0.5rem', 
      backgroundColor: theme.colors.primary, 
      color: '#FFF', 
      border: '3px solid #5C4033', 
      borderRadius: '12px', 
      fontFamily: theme.fonts.header, 
      fontSize: '1.5rem',
      cursor: 'pointer', 
      boxShadow: '4px 4px 0px #5C4033',
      transition: 'transform 0.1s ease, box-shadow 0.1s ease'
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <div style={styles.headerIcon}>
          <Utensils size={40} />
        </div>

        <h2 style={styles.title}>Login</h2>

        <form onSubmit={handleSubmit}>
          <div style={styles.inputGroup}>
            <input 
              name="email"
              type="email" 
              placeholder="Email Address" 
              value={formData.email} 
              onChange={handleChange} 
              style={styles.input}
              required 
            />
          </div>
          
          <div style={styles.inputGroup}>
            <input 
              name="password"
              type={showPass ? "text" : "password"} 
              placeholder="Password" 
              value={formData.password} 
              onChange={handleChange} 
              style={styles.input}
              required 
            />
            <button 
              type="button" 
              onClick={() => setShowPass(!showPass)} 
              style={styles.toggleBtn}
            >
              {showPass ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button 
            type="submit" 
            style={styles.button} 
            disabled={loading}
            onMouseDown={(e) => {
                e.currentTarget.style.transform = 'translate(2px, 2px)';
                e.currentTarget.style.boxShadow = '2px 2px 0px #5C4033';
            }}
            onMouseUp={(e) => {
                e.currentTarget.style.transform = 'translate(0, 0)';
                e.currentTarget.style.boxShadow = '4px 4px 0px #5C4033';
            }}
          >
            {loading ? 'Opening Door...' : 'Enter Kitchen'}
          </button>
        </form>

        <div style={{ textAlign: 'center', marginTop: '1.5rem' }}>
          <Link 
            to="/register" 
            style={{ color: theme.colors.text.muted, fontWeight: 'bold', textDecoration: 'none', fontSize: '0.9rem' }}
          >
            New here? Sign Up
          </Link>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
